ui.notifications.notify('Applying Terror Changes, please wait');

for (const [sceneId, documents] of Object.entries(KarahaiScenes)) {
  const scene = game.scenes.get(sceneId);
  for (const data of documents.filter((d) => d.type === 'token')) {
    if (data.fled === undefined) {
      const checkAlive = data.checkAlive.reduce((acc, curr) => {
        const alive = !fromUuidSync(curr)?.isDead;
        return alive && acc;
      }, true);
      if (checkAlive) {
        await game.modules.get('pf2e-season-of-ghosts').api.changeTokens(
          [
            {
              sceneId: sceneId,
              tokenId: data.id,
              updates: {
                waypoints: [
                  {
                    x: data.location.x,
                    y: data.location.y,
                    action: 'displace',
                  },
                ],
              },
            },
          ],
          { animate: false },
        );
      }
    } else {
      const token = scene.tokens.get(data.id);
      if (token) {
        if (data.fled === true && token.getFlag('pf2e-season-of-ghosts', 'fled')) {
          const checkAlive = data.checkAlive.reduce((acc, curr) => {
            const alive = !fromUuidSync(curr)?.isDead;
            return alive && acc;
          }, true);
          if (checkAlive) {
            await game.modules.get('pf2e-season-of-ghosts').api.changeTokens(
              [
                {
                  sceneId: sceneId,
                  tokenId: data.id,
                  updates: {
                    waypoints: [
                      {
                        x: data.location.x,
                        y: data.location.y,
                        action: 'displace',
                      },
                    ],
                  },
                },
              ],
              { animate: false },
            );
          }
        } else if (data.fled === false && !token.getFlag('pf2e-season-of-ghosts', 'fled')) {
          const checkAlive = data.checkAlive.reduce((acc, curr) => {
            const alive = !fromUuidSync(curr)?.isDead;
            return alive && acc;
          }, true);
          if (checkAlive) {
            await game.modules.get('pf2e-season-of-ghosts').api.changeTokens(
              [
                {
                  sceneId: sceneId,
                  tokenId: data.id,
                  updates: {
                    waypoints: [
                      {
                        x: data.location.x,
                        y: data.location.y,
                        action: 'displace',
                      },
                    ],
                  },
                },
              ],
              { animate: false },
            );
          }
        }
      }
    }
  }
  for (const data of documents.filter((d) => d.type === 'wall')) {
    await game.modules
      .get('pf2e-season-of-ghosts')
      .api.toggleSceneEmbedded(sceneId, data.ids, 'Wall', { ds: [data.state] });
  }
  for (const data of documents.filter((d) => d.type === 'sound')) {
    await game.modules
      .get('pf2e-season-of-ghosts')
      .api.toggleHiddenState(sceneId, data.ids, 'AmbientSound', { state: [data.state] });
  }
}

for (const scene of game.scenes.filter((s) => Object.keys(KarahaiScenes).includes(s.id))) {
  for (const token of scene.tokens.filter(
    (t) =>
      t.actor.type === 'npc' &&
      !t.actor.isDead &&
      !t.actor.system.traits.value.some((t) => t === 'mindless'),
  )) {
    await token.actor.increaseCondition('frightened', { max: 1, value: 1 });
  }
}

ui.notifications.notify('Terror level is applied');

