const tokenUuids = [
  "Scene.fJXSYcWoAQHn0suD.Token.QVlGb3ZKYXbWlUDP", 
  "Scene.45ImisUzLU6zjm3C.Token.Kr1YmJ1lQ2e0Y7I1",
  "Scene.fJXSYcWoAQHn0suD.Token.05faTXVboU8j23UO",
  "Scene.45ImisUzLU6zjm3C.Token.K3jaGbGNz7QdCduw", 
  "Scene.fJXSYcWoAQHn0suD.Token.QDtbcx7ky8bExoi7", 
  "Scene.45ImisUzLU6zjm3C.Token.FyvGvZyG2IQSvt8K", 
  "Scene.fJXSYcWoAQHn0suD.Token.PdHIMAidgBkBCCC8",
  "Scene.45ImisUzLU6zjm3C.Token.cBrQBi5OHHqBI176", 
];
let fled = undefined;
for (const uuid of tokenUuids) {
  const token = await fromUuid(uuid);
  if (token) {
    if (fled === undefined) {
      fled = !token.getFlag("pf2e-season-of-ghosts", "fled");
    }
    token.setFlag("pf2e-season-of-ghosts", "fled", fled);
  }
}
if (fled) {
  ui.notifications.notify("The mercenaries have fled! Set the Terror level again to move the tokens.");
} else {
  ui.notifications.notify("The mercenaries have returned! Set the Terror level again to move the tokens.");
}

Reinforcements.command:
const karahaiScenes = [
  "LYezfbUJYNl3fn4o",
  "fJXSYcWoAQHn0suD",
  "45ImisUzLU6zjm3C",
];
const reinforcedActors = ["Shrine Maiden", "Exorcist", "Mercenary Enforcer"];
for (const sceneId of karahaiScenes) {
  const scene = game.scenes.get(sceneId);
  for (const curToken of scene.tokens) {
    if (reinforcedActors.some((m) => curToken.actor.name.includes(m))) {
      curToken.actor.update({ "system.attributes.hp.value": curToken.actor.system.attributes.hp.max });
      curToken.setFlag("pf2e-season-of-ghosts", "fled", false);
    }
  }
}
ui.notifications.notify("Reinforcement have arrived! Set the Terror level again to move the tokens.");

