Mago Kai fled.command:
const tokenUuids = [
    "Scene.fJXSYcWoAQHn0suD.Token.q5c0UuqER8Hjb5K1",
];
let fled = undefined;
for (const uuid of tokenUuids) {
  const token = await fromUuid(uuid);
  if (token) {
    if (fled === undefined) {
      fled = !token.getFlag("pf2e-season-of-ghosts", "fled");
    }
    token.setFlag("pf2e-season-of-ghosts", "fled", fled);
  }
}
if (fled) {
  ui.notifications.notify("Mago Kai has fled! Set the Terror level again to move the token.");
} else {
  ui.notifications.notify("Mago Kai has returned! Set the Terror level again to move the token.");
}

