      const checkAlive = data.checkAlive.reduce((acc, curr) => {
        const alive = !fromUuidSync(curr)?.isDead;
        return alive && acc;
      }, true);
      if (checkAlive) {
        await game.modules.get('pf2e-season-of-ghosts').api.changeTokens(
          [
            {
              sceneId: sceneId,
              tokenId: data.id,
              updates: {
                waypoints: [
                  {
                    x: data.location.x,
                    y: data.location.y,
                    action: 'displace',
                  },
                ],
              },
            },
          ],
          { animate: false },
        );
      }
    } else {
      const token = scene.tokens.get(data.id);
      if (token) {
        if (data.fled === true && token.getFlag('pf2e-season-of-ghosts', 'fled')) {
          const checkAlive = data.checkAlive.reduce((acc, curr) => {
            const alive = !fromUuidSync(curr)?.isDead;
            return alive && acc;
          }, true);
          if (checkAlive) {
            await game.modules.get('pf2e-season-of-ghosts').api.changeTokens(
              [
                {
                  sceneId: sceneId,
                  tokenId: data.id,
                  updates: {
                    waypoints: [
                      {
                        x: data.location.x,
                        y: data.location.y,
                        action: 'displace',
                      },
                    ],
                  },
                },
              ],
              { animate: false },
            );
          }
        } else if (data.fled === false && !token.getFlag('pf2e-season-of-ghosts', 'fled')) {
          const checkAlive = data.checkAlive.reduce((acc, curr) => {
            const alive = !fromUuidSync(curr)?.isDead;
            return alive && acc;
          }, true);
          if (checkAlive) {
            await game.modules.get('pf2e-season-of-ghosts').api.changeTokens(
              [
                {
                  sceneId: sceneId,
                  tokenId: data.id,
                  updates: {
                    waypoints: [
                      {
                        x: data.location.x,
                        y: data.location.y,
                        action: 'displace',
                      },
                    ],
                  },
                },
              ],
              { animate: false },
            );
          }
        }
      }
    }
  }
  for (const data of documents.filter((d) => d.type === 'sound')) {
    await game.modules
      .get('pf2e-season-of-ghosts')
      .api.toggleHiddenState(sceneId, data.ids, 'AmbientSound', { state: [data.state] });
