const tokenUuids = [
  "Scene.LYezfbUJYNl3fn4o.Token.yWyC2mkCJcvyvUQq",
  "Scene.LYezfbUJYNl3fn4o.Token.aqiuJhaTN0zCleba",
  "Scene.fJXSYcWoAQHn0suD.Token.E0rGMJlhivwT21F7",
  "Scene.fJXSYcWoAQHn0suD.Token.cGXICmLj3B2dHFIX",
  "Scene.45ImisUzLU6zjm3C.Token.e8DxJf5AClV0JzB9",
  "Scene.45ImisUzLU6zjm3C.Token.BRyyf3QaFEBe8ihX",
];

let fled = undefined;
for (const uuid of tokenUuids) {
  const token = await fromUuid(uuid);
  if (token) {
    if (fled === undefined) {
      fled = !token.getFlag("pf2e-season-of-ghosts", "fled");
    }
    token.setFlag("pf2e-season-of-ghosts", "fled", fled);
  }
}
if (fled) {
  ui.notifications.notify("The exorcists have fled! Set the Terror level again to move the tokens.");
} else {
  ui.notifications.notify("The exorcists have returned! Set the Terror level again to move the tokens.");
}

